import { readFile } from "node:fs/promises";
import { join } from "node:path";

import { describe, expect, test } from "bun:test";

const actionDir = join(import.meta.dirname, "..");
const repoRoot = join(actionDir, "..", "..", "..");
const skillsDir = join(repoRoot, "claude-plugins/autopilot/skills");

const replySkillFiles = [
  join(skillsDir, "pr:resolve", "SKILL.md"),
  join(skillsDir, "pr:answer", "SKILL.md"),
];

describe("reply reference-formatting wiring", () => {
  test.each(replySkillFiles)("%s instructs replies to link commit SHAs", async (file) => {
    const content = await readFile(file, "utf8");
    expect(content).toContain("render the SHA as a markdown link");
  });

  test.each(replySkillFiles)("%s instructs replies to link doc and section references", async (file) => {
    const content = await readFile(file, "utf8");
    expect(content).toContain("link any file, doc, skill, agent, or section you cite");
  });

  test.each(replySkillFiles)("%s instructs replies to link CHECK- rule codes per pr:review §2.5", async (file) => {
    const content = await readFile(file, "utf8");
    expect(content).toContain("`CHECK-` rule code");
    expect(content).toContain("pr:review/SKILL.md#25-rule-codes");
  });

  // Issue #387: the mandate alone was ignored downstream ("Fixed in 3baf978" with a
  // bare SHA) — the copied reply template must itself demonstrate the linked form.
  test.each(replySkillFiles)("%s demonstrates the linked-SHA form in a reply template", async (file) => {
    const content = await readFile(file, "utf8");
    expect(content).toContain("Fixed in [<sha>](<repo-commit-url>/<sha>)");
  });

  test.each(replySkillFiles)("%s instructs a bare-reference self-check before posting", async (file) => {
    const content = await readFile(file, "utf8");
    expect(content).toContain("bare 7–40-char hex token");
  });
});
</file>

