1	/**
2	 * Pure parsing and diff-hunk validation for the model's review/reaction output.
3	 *
4	 * Extracted from submitReview.ts / reactToComment.ts so this logic is unit-testable
5	 * without importing those modules (which run their submission pipeline on import).
6	 * No side effects, no Octokit, no env access. Model output is validated with Zod at
7	 * the parse boundary — malformed/truncated JSON yields null, never a thrown error.
8	 */
9	import { z } from "zod";
10	
11	/** Inline comment on a specific file/line in the PR. */
12	export const inlineCommentSchema = z.object({
13	  path: z.string(),
14	  line: z.number(),
15	  body: z.string(),
16	  /** First line of a multi-line range; omit for a single-line comment (`line` is then the only line). */
17	  startLine: z.number().optional(),
18	  /** Verbatim replacement for the anchored line(s), rendered as a GitHub `suggestion` block. */
19	  suggestion: z.string().optional(),
20	});
21	export type InlineComment = z.infer<typeof inlineCommentSchema>;
22	
23	/** Structured output from a Claude review (lenient: missing fields get defaults). */
24	export const structuredOutputSchema = z.object({
25	  verdict: z.enum(["approve", "requestChanges", "comment"]).catch("comment"),
26	  reviewComment: z.string().catch("Review completed."),
27	  inlineComments: z.array(inlineCommentSchema).catch([]),
28	});
29	export type StructuredOutput = z.infer<typeof structuredOutputSchema>;
30	
31	/** Target for thread resolution by file location. */
32	export const resolveTargetSchema = z.object({
33	  path: z.string(),
34	  line: z.number(),
35	});
36	export type ResolveTarget = z.infer<typeof resolveTargetSchema>;
37	
38	/** Structured output from a Claude comment reaction. */
39	export const reactionOutputSchema = z.object({
40	  reply: z.string().catch(""),
41	  resolveComments: z.array(resolveTargetSchema).catch([]),
42	  updatedVerdict: z.enum(["approve", "requestChanges", "comment"]).nullable().catch(null),
43	  updatedReviewComment: z.string().nullable().catch(null),
44	});
45	export type ReactionOutput = z.infer<typeof reactionOutputSchema>;
46	
47	/** A valid (commentable) line location in the PR diff. */
48	export interface ValidLine {
49	  path: string;
50	  line: number;
51	}
52	
53	/**
54	 * Trim, JSON-parse (never throwing), and validate against a Zod schema.
55	 * Returns null for empty/"null" input, malformed JSON, or a schema mismatch.
56	 */
57	function parseJsonWithSchema<T>(rawOutput: string, schema: z.ZodType<T>): T | null {
58	  const trimmed = rawOutput.trim();
59	  if (!trimmed || trimmed === "null") {
60	    return null;
61	  }
62	
63	  let parsed: unknown;
64	  try {
65	    parsed = JSON.parse(trimmed);
66	  } catch {
67	    return null;
68	  }
69	
70	  const result = schema.safeParse(parsed);
71	  return result.success ? result.data : null;
72	}
73	
74	/**
75	 * Repair whitespace escape sequences the review model over-escaped.
76	 *
77	 * Under strict `json_schema` output the model sometimes serializes a line break
78	 * as a literal backslash-n (`\\n`) instead of a control newline, so after
79	 * `JSON.parse` the string carries the two characters `\` + `n` and GitHub renders
80	 * the body as one wall of text with visible `\n` (the defect this fixes). This
81	 * restores the real characters in a single pass — `\r\n`/`\r`/`\n` become a
82	 * newline, `\t` a tab — so an emitted newline can never be re-matched.
83	 *
84	 * Whole-field guard: when the text already holds a real newline the model
85	 * produced structure, so it is returned untouched. That protects a healthy
86	 * multi-paragraph body legitimately quoting `` `\n` `` inside a code span from
87	 * being rewritten. The confirmed defect is uniform — one JSON string value is
88	 * either wholly over-escaped or not — so the guard misses nothing real.
89	 *
90	 * Residual ambiguity: after `JSON.parse` an intentionally-literal `\n`/`\t` (or a
91	 * backslash path such as `C:\newfolder`) in a single-line field is byte-identical
92	 * to an over-escaped newline and is converted. This is rare, applies only to
93	 * prose fields (callers leave committed `suggestion` code untouched), and beats
94	 * leaving every multi-line body broken.
95	 */
96	export function repairOverEscapedWhitespace(text: string): string {
97	  if (text.includes("\n")) return text;
98	  return text.replaceAll(/\\r\\n|\\r|\\n|\\t/g, (match) => (match === "\\t" ? "\t" : "\n"));
99	}
100	
101	/**
102	 * Parse and validate structured review output from Claude (null on any failure).
103	 * Repairs over-escaped whitespace in the prose fields (`reviewComment`, inline
104	 * `body`); an inline `suggestion` is committed verbatim, so it is left untouched.
105	 */
106	export function parseStructuredOutput(rawOutput: string): StructuredOutput | null {
107	  const parsed = parseJsonWithSchema(rawOutput, structuredOutputSchema);
108	  if (!parsed) return null;
109	  return {
110	    ...parsed,
111	    reviewComment: repairOverEscapedWhitespace(parsed.reviewComment),
112	    inlineComments: parsed.inlineComments.map((comment) => ({
113	      ...comment,
114	      body: repairOverEscapedWhitespace(comment.body),
115	    })),
116	  };
117	}
118	
119	/**
120	 * Parse and validate structured reaction output from Claude (null on any failure).
121	 * Repairs over-escaped whitespace in the prose fields (`reply`, `updatedReviewComment`).
122	 */
123	export function parseReactionOutput(rawOutput: string): ReactionOutput | null {
124	  const parsed = parseJsonWithSchema(rawOutput, reactionOutputSchema);
125	  if (!parsed) return null;
126	  return {
127	    ...parsed,
128	    reply: repairOverEscapedWhitespace(parsed.reply),
129	    updatedReviewComment:
130	      parsed.updatedReviewComment === null
131	        ? null
132	        : repairOverEscapedWhitespace(parsed.updatedReviewComment),
133	  };
134	}
